const asaasAPI = require('../lib/index');
const constants = require('../lib/constants');
const Customers = require('../lib/customers');

test('Configuração padrão',()=>{
    expect(asaasAPI.SANDBOX).toBe(constants.SANDBOX);
    expect(asaasAPI.PRODUCTION).toBe(constants.PRODUCTION);

    expect(asaasAPI._config).toEqual({
        environment: constants.SANDBOX,
        apiKey: '',
        version: 'v3',
        debug: false
    });

    expect(asaasAPI.customers).toBeInstanceOf(Customers);
});

test('Método config',()=>{
    asaasAPI.config({
        environment: asaasAPI.PRODUCTION,
        version: 'v5'
    });

    expect(asaasAPI._config).toEqual({
        environment: constants.PRODUCTION,
        apiKey: '',
        version: 'v5',
        debug: false
    });
});
